import React from "react";
import { Trash, Eye, Book } from "react-bootstrap-icons";
import { Card, Button, Container, Row, Col } from "react-bootstrap";
import { Link } from "react-router-dom";
import { listCards } from "../utils/api/index.js";

function Decks({ decks }) {
  return decks.map((item, index) => {
    const cardLength = getCardLength(item.id);
    return (
      <Card className="mt-5" key={index}>
        <Card.Body>
          <Container>
            <Row>
              <Col>
                <Card.Title>{item.name}</Card.Title>
              </Col>
              <Col>
                <p className="text-right">{cardLength} cards</p>
              </Col>
            </Row>
          </Container>
          <Row>
            <Col>
              <Card.Text className="m-3">{item.description}</Card.Text>
            </Col>
          </Row>
          <Row>
            <Col>
              <Button variant="secondary" className="m-1">
                <Eye />
                View
              </Button>
              <Link to={`/deck/${item.id}/study`}>
                <Button>
                  <Book />
                  Study
                </Button>
              </Link>
            </Col>
            <Col className="col-sm-1 col-lg-1 mr-lg-1">
              <Button variant="danger" className="m-1">
                <Trash />
              </Button>
            </Col>
          </Row>
        </Card.Body>
      </Card>
    );
  });
}

async function getCardLength(id) {
  const cards = await listCards(id);
  return cards.length;
}

export default Decks;
